// The ensures of det_remove_l2_entry is `({A_conjunction}) ==> det_<f>_equal(...)`.
// In Verus, to discharge an implication-ensures we must put the antecedent in
// scope; otherwise raw `assert(r1.0 == target_l1_p)` has no justification (which
// is exactly how attempt 01 died). Re-wrap every assertion in an `if (antecedent)`
// so each conjunct of the ensures becomes a hypothesis, then pin every observable
// of (post_self_, r) to a deterministic function of (pre_self_, inputs) and chain
// the matching post1/post2 and r1/r2 equalities so z3 lines up the obligations
// inside `det_remove_l2_entry_equal`.

if ({
    &&& post1_self_.wf()
    &&& post1_self_.kernel_l4_end == pre_self_.kernel_l4_end
    &&& post1_self_.page_closure() =~= pre_self_.page_closure().remove(target_l1_p)
    &&& post1_self_.mapping_2m() == pre_self_.mapping_2m()
    &&& post1_self_.mapping_4k() =~= pre_self_.mapping_4k()
    &&& post1_self_.mapping_1g() =~= pre_self_.mapping_1g()
    &&& post1_self_.kernel_entries =~= pre_self_.kernel_entries
    &&& r1.0 == target_l1_p
    &&& r1.1@.is_init()
    &&& r1.1@.addr() == target_l1_p
    &&& post2_self_.wf()
    &&& post2_self_.kernel_l4_end == pre_self_.kernel_l4_end
    &&& post2_self_.page_closure() =~= pre_self_.page_closure().remove(target_l1_p)
    &&& post2_self_.mapping_2m() == pre_self_.mapping_2m()
    &&& post2_self_.mapping_4k() =~= pre_self_.mapping_4k()
    &&& post2_self_.mapping_1g() =~= pre_self_.mapping_1g()
    &&& post2_self_.kernel_entries =~= pre_self_.kernel_entries
    &&& r2.0 == target_l1_p
    &&& r2.1@.is_init()
    &&& r2.1@.addr() == target_l1_p
}) {
    // Returned PageMapPtr is fixed to target_l1_p in both runs.
    assert(r1.0 == target_l1_p);
    assert(r2.0 == target_l1_p);
    assert(r1.0 == r2.0);

    // Tracked PointsTo<PageMap>: both runs are initialised at the same address.
    assert(r1.1@.is_init());
    assert(r2.1@.is_init());
    assert(r1.1@.is_init() == r2.1@.is_init());
    assert(r1.1@.addr() == target_l1_p);
    assert(r2.1@.addr() == target_l1_p);
    assert(r1.1@.addr() == r2.1@.addr());

    // kernel_l4_end is preserved verbatim from pre_self_.
    assert(post1_self_.kernel_l4_end == pre_self_.kernel_l4_end);
    assert(post2_self_.kernel_l4_end == pre_self_.kernel_l4_end);
    assert(post1_self_.kernel_l4_end == post2_self_.kernel_l4_end);

    // page_closure is fixed to pre_self_.page_closure().remove(target_l1_p).
    assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(target_l1_p));
    assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(target_l1_p));
    assert(post1_self_.page_closure() =~= post2_self_.page_closure());
    assert(post1_self_.page_closure() == post2_self_.page_closure());

    // mapping_2m is preserved (== from the ensures).
    assert(post1_self_.mapping_2m() == pre_self_.mapping_2m());
    assert(post2_self_.mapping_2m() == pre_self_.mapping_2m());
    assert(post1_self_.mapping_2m() == post2_self_.mapping_2m());

    // mapping_4k is preserved (=~=, lift via ext-equality).
    assert(post1_self_.mapping_4k() =~= pre_self_.mapping_4k());
    assert(post2_self_.mapping_4k() =~= pre_self_.mapping_4k());
    assert(post1_self_.mapping_4k() =~= post2_self_.mapping_4k());
    assert(post1_self_.mapping_4k() == post2_self_.mapping_4k());

    // mapping_1g is preserved (=~=, lift via ext-equality).
    assert(post1_self_.mapping_1g() =~= pre_self_.mapping_1g());
    assert(post2_self_.mapping_1g() =~= pre_self_.mapping_1g());
    assert(post1_self_.mapping_1g() =~= post2_self_.mapping_1g());
    assert(post1_self_.mapping_1g() == post2_self_.mapping_1g());

    // kernel_entries is preserved (=~=, lift via ext-equality).
    assert(post1_self_.kernel_entries =~= pre_self_.kernel_entries);
    assert(post2_self_.kernel_entries =~= pre_self_.kernel_entries);
    assert(post1_self_.kernel_entries =~= post2_self_.kernel_entries);
    assert(post1_self_.kernel_entries == post2_self_.kernel_entries);

    // Both runs satisfy wf().
    assert(post1_self_.wf());
    assert(post2_self_.wf());
}
